Here are the public test cases for feature10_integrated_autolinking:
{
  "description": "Render plain text with email, hashtag, host-name URL, and IPv4 URL tokens converted into anchor elements without nesting anchors inside existing anchors.",
  "cases": [
    {
      "input": {
        "operation": "render_autolinks",
        "content": "- https://127.0.0.1/foo\n- <a href=\"www.domain.com\">www.domain.com</a>\n- (http://domain.com/some/path?with=query)\n- <a href=\"http://domain.com\">This text should stay</a>"
      },
      "expected_output": "<div>- <a href=\"https://127.0.0.1/foo\" rel=\"noopener noreferrer\">https://127.0.0.1/foo</a>\n- <a href=\"www.domain.com\">www.domain.com</a>\n- (<a href=\"http://domain.com/some/path?with=query\" rel=\"noopener noreferrer\">http://domain.com/some/path?with=query</a>)\n- <a href=\"http://domain.com\">This text should stay</a></div>\n"
    }
  ]
}

Here are the public test cases for feature11_emoji_detection_and_rendering:
{
  "description": "Detect configured emoji unicode, shortcode, and emoticon tokens and render matched emoji either as unicode or image markup.",
  "cases": [
    {
      "input": {
        "operation": "emoji_match",
        "text": "👨",
        "convertUnicode": true
      },
      "expected_output": "{\"hexcode\":\"1F468\",\"match\":\"👨\",\"unicode\":\"👨\"}\n"
    },
    {
      "input": {
        "operation": "emoji_match",
        "text": ":man:",
        "convertShortcode": true
      },
      "expected_output": "{\"hexcode\":\"1F468\",\"match\":\":man:\",\"shortcode\":\":man:\"}\n"
    }
  ]
}

