Here are the public test cases for feature1_markup_wrapping:
{
  "description": "Render text or empty content through a safe markup renderer using the requested outer container behavior.",
  "cases": [
    {
      "input": {
        "operation": "render_markup",
        "content": "Foo Bar",
        "tagName": "p"
      },
      "expected_output": "<p>Foo Bar</p>\n"
    },
    {
      "input": {
        "operation": "render_markup",
        "content": "Foo Bar",
        "tagName": "fragment"
      },
      "expected_output": "Foo Bar\n"
    }
  ]
}

Here are the public test cases for feature2_line_break_conversion:
{
  "description": "Convert plain-text line breaks into rendered break elements only when the input is plain text and conversion is enabled.",
  "cases": [
    {
      "input": {
        "operation": "render_markup",
        "content": "Foo\nBar"
      },
      "expected_output": "<div>Foo<br/>Bar</div>\n"
    },
    {
      "input": {
        "operation": "render_markup",
        "content": "Foo\nBar",
        "options": {
          "disableLineBreaks": true
        }
      },
      "expected_output": "<div>Foo\nBar</div>\n"
    }
  ]
}

Here are the public test cases for feature3_safe_html_sanitization:
{
  "description": "Render supported HTML fragments while removing disallowed elements and unsafe source attributes.",
  "cases": [
    {
      "input": {
        "operation": "render_markup",
        "content": "<script>alert(1)</script><p>Safe</p>"
      },
      "expected_output": "<div><p>Safe</p></div>\n"
    },
    {
      "input": {
        "operation": "render_markup",
        "content": "<div onclick=\"do()\">Click</div><a href=\"javascript:alert();\">Bad</a><img src=\"xss:confirm();\" alt=\"X\"/>"
      },
      "expected_output": "<div><div>Click</div><a>Bad</a><img alt=\"X\"/></div>\n"
    }
  ]
}

Here are the public test cases for feature4_attribute_normalization:
{
  "description": "Render allowed HTML attributes in normalized form and reject unsafe or unsupported attributes.",
  "cases": [
    {
      "input": {
        "operation": "render_markup",
        "content": "<time datetime=\"2016-01-01\">Jan</time><td colspan=\"3\" rowspan=\"6\">Cell</td><div class=\"foo-bar\" alt=\"Foo\" disabled=\"disabled\">X</div>"
      },
      "expected_output": "<div><time dateTime=\"2016-01-01\">Jan</time>Cell<div class=\"foo-bar\" alt=\"Foo\" disabled=\"\">X</div></div>\n"
    },
    {
      "input": {
        "operation": "render_markup",
        "content": "<div aria-live=\"off\" data-foo=\"bar\">X</div>"
      },
      "expected_output": "<div><div aria-live=\"off\" data-foo=\"bar\">X</div></div>\n"
    }
  ]
}

